const input = $input.item.json;

const cep = (input.cep || '').trim().replace(/\D/g, '');

// Modo 1: busca por CEP direto
if (cep.length === 8) {
  let data;
  try {
    data = await $helpers.httpRequest({
      method: 'GET',
      url: `https://viacep.com.br/ws/${cep}/json/`,
      json: true
    });
  } catch (e) {
    return [{ json: { erro: 'Falha ao consultar o serviço de CEP. Tente novamente.' } }];
  }
  if (data.erro) {
    return [{ json: { erro: 'CEP não encontrado. Verifique o número informado.' } }];
  }
  return [{ json: data }];
}

// Modo 2: busca por endereço (UF + cidade + logradouro)
const uf = (input.uf || '').trim().toUpperCase().slice(0, 2);

const cidade = (input.cidade || '')
  .trim()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-zA-Z0-9 ]/g, '')
  .trim();

const logradouro = (input.logradouro || '')
  .trim()
  .replace(/^(rua|av|avenida|alameda|travessa|estrada|rodovia|r\.|al\.)\s+/i, '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-zA-Z0-9 ]/g, '')
  .trim();

if (!uf || !cidade || !logradouro) {
  return [{ json: { erro: 'Informe um CEP de 8 dígitos OU os três campos: estado (UF), cidade e nome da rua.' } }];
}

let data;
try {
  data = await $helpers.httpRequest({
    method: 'GET',
    url: `https://viacep.com.br/ws/${uf}/${encodeURIComponent(cidade)}/${encodeURIComponent(logradouro)}/json/`,
    json: true
  });
} catch (e) {
  return [{ json: { erro: 'Falha ao consultar o serviço de endereço. Tente novamente.' } }];
}

if (data.erro) {
  return [{ json: { erro: 'Endereço não encontrado. Peça ao cliente mais detalhes.' } }];
}

if (Array.isArray(data)) {
  return data.map(d => ({ json: d }));
}

return [{ json: data }];
